import type { ComponentProps, ComponentRef } from 'react';
import { Avatar as AvatarPrimitive, useAvatar, useAvatarContext } from '@ark-ui/react/avatar';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Avatar.module.css';

type AvatarSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type AvatarRootProps = ComponentProps<typeof AvatarPrimitive.Root> & {
  size?: AvatarSize;
};
type AvatarRootProviderProps = ComponentProps<typeof AvatarPrimitive.RootProvider> & {
  size?: AvatarSize;
};

const AvatarRoot = forwardRef<ComponentRef<typeof AvatarPrimitive.Root>, AvatarRootProps>(
  function AvatarRoot({ className, size, ...props }, ref) {
    return (
      <AvatarPrimitive.Root
        ref={ref}
        data-slot="avatar-root"
        data-size={size}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AvatarRootProvider = forwardRef<
  ComponentRef<typeof AvatarPrimitive.RootProvider>,
  AvatarRootProviderProps
>(function AvatarRootProvider({ className, size, ...props }, ref) {
  return (
    <AvatarPrimitive.RootProvider
      ref={ref}
      data-slot="avatar-root-provider"
      data-size={size}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const AvatarImage = forwardRef<
  ComponentRef<typeof AvatarPrimitive.Image>,
  ComponentProps<typeof AvatarPrimitive.Image>
>(function AvatarImage({ className, ...props }, ref) {
  return (
    <AvatarPrimitive.Image
      ref={ref}
      data-slot="avatar-image"
      className={clsx(styles.image, normalizeClassName(className))}
      {...props}
    />
  );
});

const AvatarFallback = forwardRef<
  ComponentRef<typeof AvatarPrimitive.Fallback>,
  ComponentProps<typeof AvatarPrimitive.Fallback>
>(function AvatarFallback({ className, ...props }, ref) {
  return (
    <AvatarPrimitive.Fallback
      ref={ref}
      data-slot="avatar-fallback"
      className={clsx(styles.fallback, normalizeClassName(className))}
      {...props}
    />
  );
});

const AvatarContext = AvatarPrimitive.Context;

const Avatar = Object.assign(AvatarRoot, {
  Root: AvatarRoot,
  RootProvider: AvatarRootProvider,
  Image: AvatarImage,
  Fallback: AvatarFallback,
  Context: AvatarContext,
});

export { Avatar, useAvatar, useAvatarContext };
export type {
  AvatarContextProps,
  AvatarFallbackBaseProps,
  AvatarFallbackProps,
  AvatarImageBaseProps,
  AvatarImageProps,
  AvatarRootBaseProps,
  AvatarRootProviderBaseProps,
  AvatarStatusChangeDetails,
  UseAvatarContext,
  UseAvatarProps,
  UseAvatarReturn,
} from '@ark-ui/react/avatar';
export type { AvatarRootProps, AvatarRootProviderProps, AvatarSize };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--avatar-size, var(--size-md));
    height: var(--avatar-size, var(--size-md));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    position: relative;
    border-radius: var(--avatar-radius, var(--radius-full));
    background-color: var(--avatar-bg, var(--color-muted));
    color: var(--avatar-color, var(--color-foreground));
    font-size: var(--avatar-font-size, var(--text-md));
    font-weight: var(--avatar-font-weight, var(--weight-medium));
    line-height: var(--avatar-line-height, var(--line-height-text-md));
    user-select: none;
    vertical-align: middle;

    &:where([data-size='xs']) {
      --avatar-size: var(--size-xs);
      --avatar-font-size: var(--text-xs);
      --avatar-line-height: var(--line-height-text-xs);
    }

    &:where([data-size='sm']) {
      --avatar-size: var(--size-sm);
      --avatar-font-size: var(--text-sm);
      --avatar-line-height: var(--line-height-text-sm);
    }

    &:where([data-size='lg']) {
      --avatar-size: var(--size-lg);
      --avatar-font-size: var(--text-lg);
      --avatar-line-height: var(--line-height-text-lg);
    }

    &:where([data-size='xl']) {
      --avatar-size: var(--size-xl);
      --avatar-font-size: var(--text-lg);
      --avatar-line-height: var(--line-height-text-lg);
    }
  }

  .image {
    display: block;
    width: 100%;
    height: 100%;
    object-fit: var(--avatar-image-object-fit, cover);
    object-position: var(--avatar-image-object-position, center);
    border-radius: inherit;

    &[data-state='visible'] {
      display: block;
      opacity: 1;
    }

    &[data-state='hidden'] {
      display: none;
    }
  }

  .fallback {
    display: inline-flex;
    width: 100%;
    height: 100%;
    align-items: center;
    justify-content: center;
    padding: var(--avatar-fallback-padding, 0);
    background-color: var(--avatar-fallback-bg, var(--avatar-bg, var(--color-muted)));
    color: var(--avatar-fallback-color, inherit);
    border-radius: inherit;
    line-height: 1;

    &[data-state='visible'] {
      display: inline-flex;
    }

    &[data-state='hidden'] {
      display: none;
    }
  }
}
